  INDEX `idx_login_user_tenant`(`user_id` ASC, `tenant_id` ASC) USING BTREE,
  INDEX `idx_token_value`(`token_value`(255) ASC) USING BTREE,
  INDEX `idx_logout_time`(`logout_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 328 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '登录日志' ROW_FORMAT = DYNAMIC;

